func (h *handler) IngestEvents() IngestEventsHandler {
  return httptransport.NewHandler(
    func(ctx context.Context, r *http.Request) (IngestEventsRequest, error) {
      var req ingest.IngestEventsRequest
      ns, err := h.resolveNamespace(ctx)
      if err != nil { return req, err }
      req.Namespace = ns
      switch r.Header.Get("Content-Type") {
      case "application/cloudevents+json":
        var body api.IngestEventsApplicationCloudeventsPlusJSONRequestBody
        if err := json.NewDecoder(r.Body).Decode(&body); err != nil { return req, ErrorInvalidEvent{Err: err} }
        req.Events = []event.Event{body}
      default:
        return req, ErrorInvalidContentType{ContentType: r.Header.Get("Content-Type")}
      }
      return req, nil
    },
    func(ctx context.Context, params IngestEventsRequest) (IngestEventsResponse, error) {
      _, err := h.service.IngestEvents(ctx, params)
      return IngestEventsResponse{}, err
    },
    commonhttp.EmptyResponseEncoder[IngestEventsResponse](http.StatusNoContent),
    httptransport.AppendOptions(h.options, httptransport.WithOperationName("IngestEvents"), httptransport.WithErrorEncoder(errorEncoder()))...,
  )
}

func WithTelemetry(collector ingest.Collector, metricMeter metric.Meter, tracer trace.Tracer) (ingest.Collector, error) {
  ingestEventsCounter, err := metricMeter.Int64Counter("openmeter.ingest.events", metric.WithDescription("Number of events ingested"), metric.WithUnit("{event}"))
  if err != nil { return nil, fmt.Errorf("failed to create events counter: %w", err) }
  ingestErrorsCounter, err := metricMeter.Int64Counter("openmeter.ingest.errors", metric.WithDescription("Number of failed event ingests"), metric.WithUnit("{error}"))
  if err != nil { return nil, fmt.Errorf("failed to create errors counter: %w", err) }
  return &collectorTelemetry{collector: collector, tracer: tracer, ingestEventsCounter: ingestEventsCounter, ingestErrorsCounter: ingestErrorsCounter}, nil
}
